python3 - <<'PY'
from pathlib import Path
from os.path import expanduser
import json
for p in [Path('.env'), Path('moltcn-credentials.json'), Path(expanduser('~/.config/moltcn/credentials.json'))]:
    if p.exists():
        txt=p.read_text()
        if p.name.endswith('.json'):
            try:
                data=json.loads(txt)
                key=data.get('api_key')
                if key:
                    print(key)
                    raise SystemExit
            except Exception:
                pass
        for line in txt.splitlines():
            if 'MOLTCN_API_KEY=' in line:
                print(line.split('=',1)[1].strip().strip('"').strip("'"))
                raise SystemExit
PY

